import React from 'react';
import { Card, Stack, Text, Heading, Divider, Box } from '@ggui-ai/design/primitives';

interface Props {
  city?: string;
  temperature?: number;
  condition?: string;
  humidity?: number;
  windSpeed?: number;
  unit?: string;
  forecast?: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function WeatherCard(props: Props) {
  const {
    city = "Unknown City",
    temperature = 0,
    condition = "N/A",
    humidity = 0,
    windSpeed = 0,
    unit = "°C",
    forecast = []
  } = props;

  return (
    <Card padding={24} shadow="md" radius="lg" border={true}>
      <Stack gap={16}>
        {/* Header: City & Main Temp */}
        <Stack gap={4} align="center">
          <Heading level={2}>{city}</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-neutral-500, #6b7280)">Current Conditions</Text>
        </Stack>

        <Stack direction="horizontal" justify="center" align="center" gap={16}>
          <Heading level={1}>{temperature}{unit}</Heading>
          <Stack gap={0} align="center">
             <Text size="3xl">🌤️</Text>
             <Text variant="label">{condition}</Text>
          </Stack>
        </Stack>

        {/* Details: Humidity & Wind */}
        <Box paddingY={8}>
          <Stack direction="horizontal" justify="between">
            <Stack gap={4} align="center">
              <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">Humidity</Text>
              <Text weight="semibold">{humidity}%</Text>
            </Stack>
            <Stack gap={4} align="center">
              <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">Wind</Text>
              <Text weight="semibold">{windSpeed} km/h</Text>
            </Stack>
          </Stack>
        </Box>

        <Divider margin={8} />

        {/* Forecast Strip */}
        <Stack direction="horizontal" justify="between" align="center" gap={8}>
          {forecast.map((item, index) => (
            <Stack key={index} gap={4} align="center">
              <Text variant="caption" weight="medium">{item.day ?? '-'}</Text>
              <Text size="xl">{item.icon ?? '☁️'}</Text>
              <Stack direction="horizontal" gap={4}>
                <Text variant="caption" weight="bold">{item.high ?? 0}°</Text>
                <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">{item.low ?? 0}°</Text>
              </Stack>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}
